import numpy as np

def apply_rope_2d(q, m, theta=10000.0):
    angle = m / theta
    R = np.array([[np.cos(angle), -np.sin(angle)], [np.sin(angle), np.cos(angle)]])
    return np.dot(R, q)

def run_practice():
    q = np.array([1.0, 0.0])
    out = apply_rope_2d(q, 0.0)
    assert np.allclose(out, q)
    print('[PASS] RoPE identity rotation verified.')

if __name__ == '__main__':
    run_practice()
